from state import make_state, copy_state
from reducers import normalize, collapse, project, materialize


def process_batch(entries):
    st = make_state(entries)
    raw = st["raw"]

    # dedupe
    cleaned = normalize(raw)

    # merge values for same id
    merged = collapse(cleaned)

    # Directly finalize state: pending and stable both reflect the merged results,
    # build the view once, bump version and mark frozen.
    st["pending"] = list(merged)
    st["stable"] = list(merged)
    st["view"] = project(merged)
    st["meta"]["version"] += 1
    st["meta"]["frozen"] = True

    out = materialize(st)
    return st, out


def process_incremental(prev_state, new_entries):
    st = copy_state(prev_state)
    combined = st["stable"] + new_entries

    cleaned = normalize(combined)
    merged = collapse(cleaned)

    # As with batch, finalize directly without calling stage/commit/freeze_view.
    st["pending"] = list(merged)
    st["stable"] = list(merged)
    st["view"] = project(merged)
    st["meta"]["version"] += 1
    st["meta"]["frozen"] = True

    out = materialize(st)
    return st, out


def recompute_view(st):
    st["view"] = project(st["pending"])
    return st
