def compute_metrics(raw_data=None, cleaned_data=None):
    """
    Consolidated metrics function. If raw_data is provided, computes raw_stats.
    If cleaned_data is provided, computes display metrics.
    Returns a dict with keys 'raw_stats' and 'display' (values may be None if
    corresponding input was not provided).
    """
    result = {
        "raw_stats": None,
        "display": None,
    }

    if raw_data is not None:
        result["raw_stats"] = {
            "raw_mean": sum(raw_data) / len(raw_data),
            "raw_max": max(raw_data),
            "raw_min": min(raw_data),
            "raw_range": max(raw_data) - min(raw_data),
        }

    if cleaned_data is not None:
        # Preserve original behavior: no special empty handling (will raise if empty)
        result["display"] = {
            "avg": round(sum(cleaned_data) / len(cleaned_data), 1),
            "peak": round(max(cleaned_data), 1),
            "label": "processed",
        }

    return result


def compute_raw_stats(data):
    # Delegate to consolidated function and return only the raw_stats
    return compute_metrics(raw_data=data)["raw_stats"]


def compute_quality_score(cleaned_data):
    n_zeros = sum(1 for x in cleaned_data if x == 0)
    return 1.0 - (n_zeros / len(cleaned_data)) if cleaned_data else 0.0


def summarize_for_display(data):
    # Delegate to consolidated function and return only the display summary
    return compute_metrics(cleaned_data=data)["display"]

