from models import Inventory, Wallet
from notifications import send_confirmation, send_failure_notice

inventory = Inventory()
wallet = Wallet(balance=1000)

# Idempotency registry keyed by idempotency_key
# Each entry is a dict: {"order_id": ..., "status": "in_progress" | "core_completed" | "notification_sent", "result": ...}
_idempotency = {}


def place_order_core(order_id, sku, qty, price, idempotency_key):
    """
    Core business function: reserves inventory and charges wallet.
    This function is atomic w.r.t. those two operations: if the charge fails,
    the reservation is released and the exception is re-raised.

    Idempotency_key is required to prevent duplicate application of the core effects.
    If the key has already completed the core, the previously stored result is returned.
    """
    if idempotency_key is None:
        raise ValueError("idempotency_key is required")

    entry = _idempotency.get(idempotency_key)
    if entry is not None:
        # If core already completed, return stored result (do not re-run reserve/charge)
        if entry["status"] in ("core_completed", "notification_sent"):
            return entry["result"]
        if entry["status"] == "in_progress":
            raise RuntimeError("order already in progress for this idempotency key")

    # Mark as in-progress
    _idempotency[idempotency_key] = {"order_id": order_id, "status": "in_progress", "result": None}

    total = qty * price

    # Perform reserve then charge; ensure no partial application of these effects
    try:
        inventory.reserve(sku, qty)
        try:
            wallet.charge(total)
        except Exception:
            # rollback reservation if charge fails
            inventory.release(sku, qty)
            # mark as failed by removing idempotency entry so caller may retry with same key
            _idempotency.pop(idempotency_key, None)
            raise
    except Exception:
        # Any exception: ensure we do not leave an in-progress marker
        _idempotency.pop(idempotency_key, None)
        raise

    result = {"order_id": order_id, "charged": total, "reserved": qty}
    # Mark core as completed and store result
    _idempotency[idempotency_key] = {"order_id": order_id, "status": "core_completed", "result": result}
    return result


def place_order(order_id, sku, qty, price, idempotency_key):
    """
    Wrapper that ensures the core business effects succeed first, then performs the external notification.
    Uses idempotency_key to prevent duplicate core effects on retries. Notification is attempted only
    after a successful core. If notification fails, send_failure_notice is invoked; business effects
    remain persisted.
    """
    # Ensure core business effects
    result = place_order_core(order_id, sku, qty, price, idempotency_key)

    entry = _idempotency.get(idempotency_key)
    # If notification already sent, return the result immediately
    if entry and entry.get("status") == "notification_sent":
        return result

    # Attempt to send confirmation (external flaky side-effect)
    try:
        send_confirmation(order_id)
    except Exception as e:
        # Notification failed; record the failure notice (must occur after attempting send_confirmation)
        try:
            send_failure_notice(order_id, str(e))
        finally:
