from enum import Enum
from typing import Any, Dict, Mapping, Set


class Status(str, Enum):
    DRAFT = 'draft'
    SUBMITTED = 'submitted'
    APPROVED = 'approved'
    REJECTED = 'rejected'


_VALID_TRANSITIONS = {
    Status.DRAFT: {Status.SUBMITTED},
    Status.SUBMITTED: {Status.APPROVED, Status.REJECTED},
    Status.APPROVED: set(),
    Status.REJECTED: set(),
}


class TransitionError(ValueError):
    '''Raised when an invalid status transition is attempted.'''


def _to_status(value) -> Status:
    '''Normalize a value to a Status enum. Accepts Status or recognizable string.'''
    if isinstance(value, Status):
        return value
    try:
        return Status(value)
    except ValueError:
        raise ValueError(f'unknown status: {value!r}')


def get_status(item: Mapping[str, Any]) -> Status:
    '''Return the Status for the given item.

    Raises KeyError if 'status' is missing and ValueError if the status is invalid.
    '''
    try:
        return _to_status(item['status'])
    except KeyError:
        raise KeyError("item missing 'status' key")


def transition(item: Dict[str, Any], new_status) -> None:
    '''Attempt to transition item['status'] to new_status.

    new_status may be a Status or a string. The item's 'status' is updated to the
    canonical string value of the target status on success. Raises TransitionError
    for invalid transitions.
    '''
    current = get_status(item)
    target = _to_status(new_status)
    allowed: Set[Status] = _VALID_TRANSITIONS.get(current, set())
    if target not in allowed:
        raise TransitionError(f'cannot transition from {current.value} to {target.value}')
    item['status'] = target.value


